function f(t,s){let i=0,n=[],p=0;for(let r=0;r<t.length;r++)t[r]==="("&&i++,t[r]===")"&&i--,t[r]===s&&i===0&&(n.push(t.substring(p,r)),p=r+1);return n.push(t.substring(p)),n}function a(t){return f(t,"-").map((s,i)=>i>0?"-"+s:s).map(s=>f(s,"+")).flat().map(s=>s.trim()).filter(s=>s!=="")}function e(t){return t.split("{")[0]+"{"+t.split("{")[1].split("}")[0].split(";").sort().join(";")+"}"+(t.split("}")[1]??"")}function o(t){return t.substring(1)}function c(t){return t.substring(0,t.length-1)}export{c as a,e as b,f as c,a as d,o as s};
